import { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { toast } from "react-toastify";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";
import { getStockBySymbol, getStockHistory } from "../services/stockService";
import { addToWatchlist, removeFromWatchlist } from "../store/slices/stockSlice";
import { buyStock, sellStock } from "../store/slices/portfolioSlice";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

export default function StockDetail() {
  const { symbol } = useParams();
  const [stock, setStock] = useState(null);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [period, setPeriod] = useState("1M");
  const [watchlist, setWatchlist] = useState([]);

  useEffect(() => {
    const savedWatchlist = localStorage.getItem("watchlist");
    if (savedWatchlist) {
      setWatchlist(JSON.parse(savedWatchlist));
    }
  }, []);

  useEffect(() => {
    fetchStockData();
    
    // Auto-refresh every 30 seconds
    const interval = setInterval(fetchStockData, 30000);
    return () => clearInterval(interval);
  }, [symbol, period]);

  const fetchStockData = async () => {
    setLoading(true);
    try {
      const [stockData, historyData] = await Promise.all([
        getStockBySymbol(symbol),
        getStockHistory(symbol, period)
      ]);
      setStock(stockData);
      setHistory(historyData);
    } catch (error) {
      console.error("Error fetching stock data:", error);
    } finally {
      setLoading(false);
    }
  };

  const toggleWatchlist = () => {
    const newWatchlist = watchlist.includes(symbol)
      ? watchlist.filter(s => s !== symbol)
      : [...watchlist, symbol];
    
    setWatchlist(newWatchlist);
    localStorage.setItem("watchlist", JSON.stringify(newWatchlist));
  };

  const isInWatchlist = watchlist.includes(symbol);

  // Calculate min and max for chart scaling
  const prices = history.map(h => h.price);
  const minPrice = Math.min(...prices);
  const maxPrice = Math.max(...prices);
  const priceRange = maxPrice - minPrice;

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading stock data...</p>
        </div>
      </div>
    );
  }

  if (!stock) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-gray-600 mb-4">Stock not found</p>
          <Link to="/markets" className="text-indigo-600 hover:text-indigo-800">
            Back to Markets
          </Link>
        </div>
      </div>
    );
  }

  const isPositive = stock.change >= 0;

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        {/* Breadcrumb */}
        <div className="mb-4">
          <Link to="/markets" className="text-indigo-600 hover:text-indigo-800 flex items-center">
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            Back to Markets
          </Link>
        </div>

        {/* Stock Header */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-6">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center">
            <div>
              <h1 className="text-3xl font-bold text-gray-800">{stock.symbol}</h1>
              <p className="text-lg text-gray-600">{stock.name}</p>
              <span className="inline-block bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-sm mt-2">
                {stock.sector}
              </span>
            </div>
            <div className="mt-4 md:mt-0 text-right">
              <p className="text-4xl font-bold text-gray-800">
                ₹{stock.price.toLocaleString('en-IN')}
              </p>
              <div className={`flex items-center justify-end ${isPositive ? "text-green-600" : "text-red-600"}`}>
                <svg 
                  className={`w-5 h-5 mr-1 ${isPositive ? "rotate-0" : "rotate-180"}`} 
                  fill="none" 
                  stroke="currentColor" 
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
                <span className="text-lg font-semibold">
                  {isPositive ? "+" : ""}{stock.change.toFixed(2)} ({isPositive ? "+" : ""}{stock.changePercent.toFixed(2)}%)
                </span>
              </div>
            </div>
          </div>

          <div className="mt-6 flex gap-4">
            <button
              onClick={toggleWatchlist}
              className={`flex items-center px-6 py-2 rounded-lg font-semibold transition-colors duration-200 ${
                isInWatchlist
                  ? "bg-yellow-100 text-yellow-700 hover:bg-yellow-200"
                  : "bg-indigo-600 text-white hover:bg-indigo-700"
              }`}
            >
              <svg 
                className="w-5 h-5 mr-2" 
                fill={isInWatchlist ? "currentColor" : "none"} 
                stroke="currentColor" 
                viewBox="0 0 24 24"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
              </svg>
              {isInWatchlist ? "Remove from Watchlist" : "Add to Watchlist"}
            </button>
            
            <button className="flex items-center px-6 py-2 bg-green-600 text-white rounded-lg font-semibold hover:bg-green-700 transition-colors duration-200">
              <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
              </svg>
              Buy
            </button>
            
            <button className="flex items-center px-6 py-2 bg-red-600 text-white rounded-lg font-semibold hover:bg-red-700 transition-colors duration-200">
              <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
              </svg>
              Sell
            </button>
          </div>
        </div>

        {/* Chart Section */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-gray-800">Price Chart</h2>
            <div className="flex gap-2">
              {["1D", "1W", "1M", "1Y"].map((p) => (
                <button
                  key={p}
                  onClick={() => setPeriod(p)}
                  className={`px-3 py-1 rounded text-sm font-semibold transition-colors duration-200 ${
                    period === p
                      ? "bg-indigo-600 text-white"
                      : "bg-gray-100 text-gray-700 hover:bg-gray-200"
                  }`}
                >
                  {p}
                </button>
              ))}
            </div>
          </div>
          
          {/* Simple SVG Chart */}
          <div className="h-64 w-full">
            <svg className="w-full h-full" viewBox={`0 0 ${history.length} 100`} preserveAspectRatio="none">
              {/* Grid lines */}
              {[0, 25, 50, 75, 100].map((y) => (
                <line
                  key={y}
                  x1="0"
                  y1={y}
                  x2={history.length}
                  y2={y}
                  stroke="#e5e7eb"
                  strokeWidth="0.5"
                />
              ))}
              
              {/* Price line */}
              <polyline
                fill="none"
                stroke={isPositive ? "#16a34a" : "#dc2626"}
                strokeWidth="2"
                points={history.map((h, i) => {
                  const normalizedPrice = ((h.price - minPrice) / priceRange) * 80 + 10;
                  return `${i},${100 - normalizedPrice}`;
                }).join(" ")}
              />
              
              {/* Area under the line */}
              <polygon
                fill={isPositive ? "rgba(22, 163, 74, 0.1)" : "rgba(220, 38, 38, 0.1)"}
                points={`
                  0,100
                  ${history.map((h, i) => {
                    const normalizedPrice = ((h.price - minPrice) / priceRange) * 80 + 10;
                    return `${i},${100 - normalizedPrice}`;
                  }).join(" ")}
                  ${history.length - 1},100
                `}
              />
            </svg>
          </div>
          
          <div className="flex justify-between text-sm text-gray-500 mt-2">
            <span>{history[0]?.date}</span>
            <span>{history[history.length - 1]?.date}</span>
          </div>
        </div>

        {/* Stock Details Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">Open</p>
            <p className="text-xl font-bold text-gray-800">₹{stock.open.toLocaleString('en-IN')}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">Previous Close</p>
            <p className="text-xl font-bold text-gray-800">₹{stock.previousClose.toLocaleString('en-IN')}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">Day High</p>
            <p className="text-xl font-bold text-gray-800">₹{stock.dayHigh.toLocaleString('en-IN')}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">Day Low</p>
            <p className="text-xl font-bold text-gray-800">₹{stock.dayLow.toLocaleString('en-IN')}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">Volume</p>
            <p className="text-xl font-bold text-gray-800">{stock.volume}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">Market Cap</p>
            <p className="text-xl font-bold text-gray-800">{stock.marketCap}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">52W High</p>
            <p className="text-xl font-bold text-gray-800">₹{(stock.dayHigh * 1.2).toFixed(2)}</p>
          </div>
          <div className="bg-white rounded-lg shadow-md p-4">
            <p className="text-sm text-gray-600 mb-1">52W Low</p>
            <p className="text-xl font-bold text-gray-800">₹{(stock.dayLow * 0.8).toFixed(2)}</p>
          </div>
        </div>
      </div>
    </div>
  );
}
